-- 3) Experience display_order = 3
UPDATE experiences SET user_reviews = '[{"name":"Carlos G.","country":"🇪🇸 Spain","rating":5,"date":"2026-01-23","text":"Absolutely fantastic. We discovered flavors we didn''t know existed. The pastéis de bacalhau fresh from the fryer were incredible!","source":"getyourguide","verified":true},{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-12-22","text":"10 tastings in 3 hours — we were absolutely stuffed by the end! The bacalhau and the local cheese were standouts. Highly recommend going hungry.","source":"viator","verified":true},{"name":"Thomas M.","country":"🇩🇪 Germany","rating":5,"date":"2025-12-06","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"viator","verified":true},{"name":"Jennifer K.","country":"🇺🇸 United States","rating":5,"date":"2025-10-04","text":"Perfect mix of food, culture, and walking through beautiful neighborhoods. Portions were generous — we skipped dinner afterwards!","source":"getyourguide","verified":true},{"name":"Katrine H.","country":"🇩🇰 Denmark","rating":4,"date":"2025-10-03","text":"Good food tour but I''ve done better in other cities. The wine and cheese stop was the highlight. Guide was friendly and informative.","source":"viator","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-09-07","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"viator","verified":true},{"name":"Patrick O.","country":"🇮🇪 Ireland","rating":5,"date":"2025-07-18","text":"We''re vegetarian and they accommodated us beautifully at every stop. Thoughtful and well-organized. Will recommend to everyone.","source":"getyourguide","verified":true},{"name":"Marco R.","country":"🇮🇹 Italy","rating":4,"date":"2025-07-12","text":"Good variety of food and drink. Some stops were better than others, but overall a great introduction to Lisbon''s food scene.","source":"viator","verified":true},{"name":"Nadia K.","country":"🇨🇦 Canada","rating":5,"date":"2025-04-06","text":"Really enjoyed this. Good organization, friendly staff, and a memorable experience. Will definitely recommend to friends.","source":"viator","verified":true},{"name":"Nina V.","country":"🇷🇺 Russia","rating":4,"date":"2025-02-24","text":"A lovely experience overall. Would have liked a bit more variety in the tastings, but the quality was top-notch and the guide was wonderful.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 3;

-- 4) Experience display_order = 4
UPDATE experiences SET user_reviews = '[{"name":"Mieke D.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-12-29","text":"Brilliant! Everything ran smoothly and the quality was exceptional. This is exactly the kind of experience that makes travel special.","source":"getyourguide","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-12-28","text":"Great experience, very well organized. The guide was knowledgeable and friendly. We had an amazing time. Don''t miss this!","source":"viator","verified":true},{"name":"Patrick O.","country":"🇮🇪 Ireland","rating":5,"date":"2025-10-30","text":"Took my parents on this tour — they loved every minute. Well-paced, not too much walking, and the food was exceptional. A must-do!","source":"viator","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":5,"date":"2025-10-25","text":"10 tastings in 3 hours — we were absolutely stuffed by the end! The bacalhau and the local cheese were standouts. Highly recommend going hungry.","source":"getyourguide","verified":true},{"name":"Erik J.","country":"🇳🇴 Norway","rating":5,"date":"2025-08-30","text":"We''re vegetarian and they accommodated us beautifully at every stop. Thoughtful and well-organized. Will recommend to everyone.","source":"viator","verified":true},{"name":"Katrine H.","country":"🇩🇰 Denmark","rating":5,"date":"2025-07-16","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name":"Pablo V.","country":"🇪🇸 Spain","rating":5,"date":"2025-04-17","text":"Such an authentic experience. Small group, no tourist traps. Our guide took us to a local tasca where we were the only foreigners. Pure gold.","source":"getyourguide","verified":true},{"name":"Miguel A.","country":"🇲🇽 Mexico","rating":5,"date":"2025-03-21","text":"Perfect mix of food, culture, and walking through beautiful neighborhoods. Portions were generous — we skipped dinner afterwards!","source":"viator","verified":true},{"name":"Marco R.","country":"🇮🇹 Italy","rating":5,"date":"2025-02-24","text":"As a foodie, this was the highlight of our Lisbon trip. The market stop alone was worth the price. Learned so much about Portuguese flavors.","source":"viator","verified":true},{"name":"Giulia P.","country":"🇮🇹 Italy","rating":5,"date":"2025-02-05","text":"We did this on our first day and it set the tone for the entire trip. Now we know exactly what to order at restaurants. The wine pairings were perfect.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 4;

