UPDATE experiences SET user_reviews = '[{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-10-30","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"getyourguide","verified":true},{"name":"Giulia P.","country":"🇮🇹 Italy","rating":5,"date":"2025-09-18","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"viator","verified":true},{"name":"Lisa B.","country":"🇩🇪 Germany","rating":5,"date":"2025-08-22","text":"A long but rewarding day. The views were absolutely breathtaking. Tip: bring a jacket — it can be windy at the coast!","source":"viator","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":5,"date":"2025-06-26","text":"Exceeded expectations! The included stops were well-chosen and the free time was enough to explore at our own pace.","source":"getyourguide","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-06-10","text":"Best day trip of our Portugal holiday. Every stop was more beautiful than the last. The small group made it feel personal.","source":"viator","verified":true},{"name":"Isabel F.","country":"🇦🇷 Argentina","rating":5,"date":"2025-05-15","text":"Booked last minute and so glad we did. This was the most photogenic day of our entire trip. Every stop was Instagram-worthy.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-05-13","text":"Well-organized from start to finish. Pick-up was on time, the guide was fantastic, and we covered so much ground. Worth every euro.","source":"getyourguide","verified":true},{"name":"Michael R.","country":"🇺🇸 United States","rating":5,"date":"2025-04-29","text":"The highlight of our trip to Portugal. Stunning landscapes, charming villages, and a guide who clearly loves sharing their country.","source":"viator","verified":true},{"name":"Wei L.","country":"🇨🇳 China","rating":5,"date":"2025-03-23","text":"Brilliant! Everything ran smoothly and the quality was exceptional. This is exactly the kind of experience that makes travel special.","source":"viator","verified":true},{"name":"Nadia K.","country":"🇨🇦 Canada","rating":5,"date":"2025-02-17","text":"We were a group of 6 and all agreed this was the best experience we booked. Comfortable transport, beautiful scenery, amazing guide.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 5;

-- 6) Experience display_order = 6
UPDATE experiences SET user_reviews = '[{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-11-21","text":"A must-do when visiting Lisbon. The combination of history, culture, and stunning views was perfect. Small group was a big plus.","source":"getyourguide","verified":true},{"name":"Michael R.","country":"🇺🇸 United States","rating":5,"date":"2025-08-15","text":"Fascinating tour through neighborhoods most tourists miss. The viewpoints were spectacular and the guide''s storytelling was captivating.","source":"viator","verified":true},{"name":"James T.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-08-01","text":"Perfect way to orient yourself in Lisbon. We went on our first day and kept returning to spots the guide showed us throughout our trip.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-07-10","text":"The architecture insights were incredible. Our guide pointed out details I would have walked past a thousand times. Eye-opening experience.","source":"getyourguide","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":4,"date":"2025-06-09","text":"Good experience overall. A few minor things could be improved but nothing significant. We had a great time. Worth it!","source":"viator","verified":true},{"name":"Yuki T.","country":"🇯🇵 Japan","rating":5,"date":"2025-06-06","text":"Loved it! A unique way to experience Lisbon. The team was professional and the activity was so much fun. Highly recommend.","source":"viator","verified":true},{"name":"Wei L.","country":"🇨🇳 China","rating":5,"date":"2025-05-13","text":"Really enjoyable and informative. The guide mixed history with modern culture perfectly. Great tips for restaurants and bars too.","source":"getyourguide","verified":true},{"name":"Rafael O.","country":"🇧🇷 Brazil","rating":5,"date":"2025-05-06","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name":"Carlos G.","country":"🇪🇸 Spain","rating":5,"date":"2025-02-26","text":"Loved the hidden alleys and secret viewpoints. This isn''t your typical tourist walk — it''s much better. Highly recommend.","source":"viator","verified":true},{"name":"Isabel F.","country":"🇦🇷 Argentina","rating":4,"date":"2025-02-10","text":"Good tour with interesting historical context. A bit long at 3 hours for those not used to walking, but the content was worth it.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 6;

-- 7) Experience display_order = 7
UPDATE experiences SET user_reviews = '[{"name":"Nina V.","country":"🇷🇺 Russia","rating":5,"date":"2025-11-25","text":"Absolutely fantastic. We discovered flavors we didn''t know existed. The pastéis de bacalhau fresh from the fryer were incredible!","source":"getyourguide","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-11-24","text":"Wonderful tour! Our guide was funny, knowledgeable, and clearly loves what she does. The sardine tasting was surprisingly amazing.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-10-27","text":"We''re vegetarian and they accommodated us beautifully at every stop. Thoughtful and well-organized. Will recommend to everyone.","source":"viator","verified":true},{"name":"Antoine D.","country":"🇫🇷 France","rating":5,"date":"2025-10-20","text":"As a foodie, this was the highlight of our Lisbon trip. The market stop alone was worth the price. Learned so much about Portuguese flavors.","source":"getyourguide","verified":true},{"name":"Lars E.","country":"🇸🇪 Sweden","rating":5,"date":"2025-09-23","text":"Exceeded all expectations. The guide''s knowledge of food history was impressive. The ginjinha tasting at that tiny bar was an unforgettable moment.","source":"viator","verified":true},{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-09-04","text":"We did this on our first day and it set the tone for the entire trip. Now we know exactly what to order at restaurants. The wine pairings were perfect.","source":"viator","verified":true},{"name":"Ana M.","country":"🇪🇸 Spain","rating":4,"date":"2025-08-07","text":"Good food tour but I''ve done better in other cities. The wine and cheese stop was the highlight. Guide was friendly and informative.","source":"getyourguide","verified":true},{"name":"Emma W.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-06-20","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":5,"date":"2025-05-02","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"viator","verified":true},{"name":"Lisa B.","country":"🇩🇪 Germany","rating":5,"date":"2025-03-02","text":"A memorable experience that we''ll be talking about for years. Professional, fun, and uniquely Portuguese. Don''t hesitate!","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 7;

-- 8) Experience display_order = 8
UPDATE experiences SET user_reviews = '[{"name":"Jan V.","country":"🇳🇱 Netherlands","rating":5,"date":"2026-01-12","text":"Incredible experience. The captain shared great stories about Lisbon''s maritime history while we sipped wine. Peaceful and beautiful.","source":"getyourguide","verified":true},{"name":"Emma W.","country":"🇬🇧 United Kingdom","rating":5,"date":"2026-01-08","text":"Magical sunset on the Tagus! The light over Lisbon was unreal. The crew was fantastic and the wine kept flowing. Absolutely perfect.","source":"viator","verified":true},{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-11-21","text":"We celebrated our anniversary on this cruise. It was intimate, the views were stunning, and the crew made us feel special. Thank you!","source":"viator","verified":true},{"name":"Erik J.","country":"🇳🇴 Norway","rating":4,"date":"2025-10-31","text":"Good experience overall. A few minor things could be improved but nothing significant. We had a great time. Worth it!","source":"getyourguide","verified":true},{"name":"Lars E.","country":"🇸🇪 Sweden","rating":5,"date":"2025-10-13","text":"Really enjoyed this! The captain let us help with the sails which was fun. Great for couples or small groups.","source":"viator","verified":true},{"name":"Olivia C.","country":"🇦🇺 Australia","rating":5,"date":"2025-09-05","text":"Relaxing and beautiful. The crew were friendly and professional. Seeing Lisbon from the water gives you a completely different perspective.","source":"viator","verified":true},{"name":"Jennifer K.","country":"🇺🇸 United States","rating":5,"date":"2025-08-04","text":"Exceeded our expectations! Everything was professionally run and the experience itself was fantastic. A must-do in Lisbon.","source":"getyourguide","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-07-30","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-06-27","text":"The atmosphere on the boat was fantastic. Good mix of people, great music, and the sunset didn''t disappoint. Will do again!","source":"viator","verified":true},{"name":"Carlos G.","country":"🇪🇸 Spain","rating":5,"date":"2025-06-07","text":"Book the sunset slot — trust me. The colors over the 25 de Abril bridge were spectacular. Comfortable boat, lovely crew.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 8;

-- 9) Experience display_order = 9
UPDATE experiences SET user_reviews = '[{"name":"Tom B.","country":"🇦🇺 Australia","rating":5,"date":"2025-12-26","text":"Great value for what you get. 2 hours on the water with drinks and snacks. The views of Belém from the river are something special.","source":"getyourguide","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":5,"date":"2025-12-21","text":"Book the sunset slot — trust me. The colors over the 25 de Abril bridge were spectacular. Comfortable boat, lovely crew.","source":"viator","verified":true},{"name":"Antoine D.","country":"🇫🇷 France","rating":5,"date":"2025-09-19","text":"A memorable experience that we''ll be talking about for years. Professional, fun, and uniquely Portuguese. Don''t hesitate!","source":"viator","verified":true},{"name":"Fatima A.","country":"🇲🇦 Morocco","rating":5,"date":"2025-08-12","text":"A lovely way to spend an evening. The boat was comfortable, not too crowded. The Fado music on board was a wonderful surprise.","source":"getyourguide","verified":true},{"name":"Mieke D.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-07-23","text":"Relaxing and beautiful. The crew were friendly and professional. Seeing Lisbon from the water gives you a completely different perspective.","source":"viator","verified":true},{"name":"Nina V.","country":"🇷🇺 Russia","rating":5,"date":"2025-06-19","text":"Really enjoyed this. Good organization, friendly staff, and a memorable experience. Will definitely recommend to friends.","source":"viator","verified":true},{"name":"Camila S.","country":"🇧🇷 Brazil","rating":5,"date":"2025-05-01","text":"The atmosphere on the boat was fantastic. Good mix of people, great music, and the sunset didn''t disappoint. Will do again!","source":"getyourguide","verified":true},{"name":"James T.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-03-29","text":"Perfect activity after a day of walking. Just sit back, relax, and enjoy the views. The Ponte 25 de Abril lit up at night was amazing.","source":"viator","verified":true},{"name":"Erik J.","country":"🇳🇴 Norway","rating":5,"date":"2025-03-26","text":"Great experience, very well organized. The guide was knowledgeable and friendly. We had an amazing time. Don''t miss this!","source":"viator","verified":true},{"name":"Olivia C.","country":"🇦🇺 Australia","rating":4,"date":"2025-02-27","text":"Nice cruise but it was a bit windy and cold. Bring a jacket! The views and wine were great though. Overall a good experience.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 9;

