UPDATE experiences SET user_reviews = '[{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-11-23","text":"A great indoor activity that surprised us all. Creative, engaging, and lots of fun. Perfect for groups of friends.","source":"getyourguide","verified":true},{"name":"Antoine D.","country":"🇫🇷 France","rating":5,"date":"2025-10-27","text":"Impressive production quality! The whole experience felt immersive and exciting. Much better than we expected. Highly recommend.","source":"viator","verified":true},{"name":"Lisa B.","country":"🇩🇪 Germany","rating":5,"date":"2025-10-15","text":"Brilliant! Everything ran smoothly and the quality was exceptional. This is exactly the kind of experience that makes travel special.","source":"viator","verified":true},{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-07-29","text":"The kids absolutely loved this. It''s great for families — everyone can participate. The themes were clever and engaging.","source":"getyourguide","verified":true},{"name":"Rafael O.","country":"🇧🇷 Brazil","rating":4,"date":"2025-07-29","text":"Good fun but not quite as challenging as we hoped. Still a great experience overall and the venue was fantastic.","source":"viator","verified":true},{"name":"Patrick O.","country":"🇮🇪 Ireland","rating":5,"date":"2025-06-29","text":"So much fun! Our group was laughing the entire time. The puzzles were clever and the setting was immersive. Great team activity!","source":"viator","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":5,"date":"2025-06-11","text":"We loved it! Challenging but not frustrating. The staff were helpful without giving too much away. Would definitely do again.","source":"getyourguide","verified":true},{"name":"Sarah M.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-03-27","text":"Loved it! A unique way to experience Lisbon. The team was professional and the activity was so much fun. Highly recommend.","source":"viator","verified":true},{"name":"Olivia C.","country":"🇦🇺 Australia","rating":5,"date":"2025-02-28","text":"Clever and entertaining. The production values were high and the whole experience was seamless. Will recommend to friends.","source":"viator","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-02-03","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 12;

