UPDATE experiences SET user_reviews = '[{"name":"Ana M.","country":"🇪🇸 Spain","rating":5,"date":"2026-01-09","text":"My husband and I are wine enthusiasts and this tour exceeded our expectations. The family-run winery was so authentic and welcoming.","source":"getyourguide","verified":true},{"name":"Emma W.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-10-30","text":"An exceptional wine tour. The guide''s knowledge was encyclopedic. We discovered grape varieties we''d never heard of. Bought several bottles!","source":"viator","verified":true},{"name":"Thomas M.","country":"🇩🇪 Germany","rating":4,"date":"2025-08-09","text":"Enjoyed the tour but wished we''d visited one more winery. The two we did see were fantastic though. Beautiful scenery along the way.","source":"viator","verified":true},{"name":"Erik J.","country":"🇳🇴 Norway","rating":4,"date":"2025-08-06","text":"Good wine tour. The guide was pleasant and informative. Some wines were better than others, but that''s part of the experience.","source":"getyourguide","verified":true},{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-07-13","text":"What a wonderful discovery! Portuguese wines are amazing and this tour was the perfect introduction. The port wine at sunset was magical.","source":"viator","verified":true},{"name":"Mieke D.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-07-06","text":"Loved it! A unique way to experience Lisbon. The team was professional and the activity was so much fun. Highly recommend.","source":"viator","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-06-22","text":"Highly recommend for anyone interested in wine. We tasted about 15 different wines and learned something new at every stop.","source":"getyourguide","verified":true},{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-03-20","text":"Well-organized tour with plenty of time at each winery. The lunch was a wonderful surprise — fresh, local, and paired perfectly.","source":"viator","verified":true},{"name":"Tom B.","country":"🇦🇺 Australia","rating":5,"date":"2025-02-11","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"viator","verified":true},{"name":"Giulia P.","country":"🇮🇹 Italy","rating":5,"date":"2025-02-10","text":"Wonderful experience! Exactly as described and even better in person. Our guide was outstanding. Highly recommended.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 13;

-- 14) Experience display_order = 14
UPDATE experiences SET user_reviews = '[{"name":"Miguel A.","country":"🇲🇽 Mexico","rating":5,"date":"2025-11-01","text":"Great experience, very well organized. The guide was knowledgeable and friendly. We had an amazing time. Don''t miss this!","source":"getyourguide","verified":true},{"name":"Sven L.","country":"🇨🇭 Switzerland","rating":5,"date":"2025-10-01","text":"An incredible encounter with nature! We spotted dolphins and the marine biologist guide made everything so educational and exciting.","source":"viator","verified":true},{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-08-24","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name":"Katrine H.","country":"🇩🇰 Denmark","rating":5,"date":"2025-06-30","text":"What a wonderful way to experience Portuguese nature. The landscapes were diverse and beautiful. Our guide was superb.","source":"getyourguide","verified":true},{"name":"Wei L.","country":"🇨🇳 China","rating":5,"date":"2025-06-20","text":"We''re avid hikers and this didn''t disappoint. The terrain was interesting and the views were magnificent. Excellent guide.","source":"viator","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-06-14","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"viator","verified":true},{"name":"Hans K.","country":"🇩🇪 Germany","rating":5,"date":"2025-05-22","text":"A must-do for anyone who appreciates the natural world. The biodiversity was surprising and the guide was excellent.","source":"getyourguide","verified":true},{"name":"Thomas M.","country":"🇩🇪 Germany","rating":5,"date":"2025-05-03","text":"Beautiful experience from start to finish. The guide was warm, funny, and incredibly knowledgeable. Would do it again in a heartbeat.","source":"viator","verified":true},{"name":"Antoine D.","country":"🇫🇷 France","rating":5,"date":"2025-05-01","text":"Breathtaking scenery and wonderful wildlife. The guide''s knowledge of the local ecosystem was impressive. A nature lover''s dream.","source":"viator","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":5,"date":"2025-03-29","text":"Really enjoyed this immersive nature experience. It felt authentic and off the beaten path. Great for eco-conscious travelers.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 14;

-- 15) Experience display_order = 15
UPDATE experiences SET user_reviews = '[{"name":"Emma W.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-12-18","text":"Exceeded all expectations. The guide''s knowledge of food history was impressive. The ginjinha tasting at that tiny bar was an unforgettable moment.","source":"getyourguide","verified":true},{"name":"Katrine H.","country":"🇩🇰 Denmark","rating":5,"date":"2025-12-02","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"viator","verified":true},{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-11-27","text":"Perfect mix of food, culture, and walking through beautiful neighborhoods. Portions were generous — we skipped dinner afterwards!","source":"viator","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-07-20","text":"As a foodie, this was the highlight of our Lisbon trip. The market stop alone was worth the price. Learned so much about Portuguese flavors.","source":"getyourguide","verified":true},{"name":"Sarah M.","country":"🇬🇧 United Kingdom","rating":4,"date":"2025-06-18","text":"Good food tour but I''ve done better in other cities. The wine and cheese stop was the highlight. Guide was friendly and informative.","source":"viator","verified":true},{"name":"Wei L.","country":"🇨🇳 China","rating":5,"date":"2025-06-06","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"viator","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-03-08","text":"Wonderful tour! Our guide was funny, knowledgeable, and clearly loves what she does. The sardine tasting was surprisingly amazing.","source":"getyourguide","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":5,"date":"2025-03-05","text":"We did this on our first day and it set the tone for the entire trip. Now we know exactly what to order at restaurants. The wine pairings were perfect.","source":"viator","verified":true},{"name":"Miguel A.","country":"🇲🇽 Mexico","rating":5,"date":"2025-03-02","text":"We had an amazing time. The attention to detail was impressive and the staff clearly care about delivering a great experience.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-02-19","text":"Absolutely fantastic. We discovered flavors we didn''t know existed. The pastéis de bacalhau fresh from the fryer were incredible!","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 15;

-- 16) Experience display_order = 16
UPDATE experiences SET user_reviews = '[{"name":"Marie C.","country":"🇫🇷 France","rating":4,"date":"2026-01-22","text":"Enjoyed the tour but wished we''d visited one more winery. The two we did see were fantastic though. Beautiful scenery along the way.","source":"getyourguide","verified":true},{"name":"Ingrid N.","country":"🇸🇪 Sweden","rating":5,"date":"2025-12-17","text":"Loved it! A unique way to experience Lisbon. The team was professional and the activity was so much fun. Highly recommend.","source":"viator","verified":true},{"name":"Camila S.","country":"🇧🇷 Brazil","rating":5,"date":"2025-10-31","text":"We''ve done wine tours in France, Italy, and Spain. This was right up there with the best. Portuguese wines deserve more recognition.","source":"viator","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":4,"date":"2025-10-07","text":"Good wine tour. The guide was pleasant and informative. Some wines were better than others, but that''s part of the experience.","source":"getyourguide","verified":true},{"name":"Olivia C.","country":"🇦🇺 Australia","rating":5,"date":"2025-09-18","text":"Beautiful drive through wine country, excellent tastings, and a knowledgeable guide. The Arrábida region is absolutely gorgeous.","source":"viator","verified":true},{"name":"Pablo V.","country":"🇪🇸 Spain","rating":5,"date":"2025-09-08","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"viator","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-08-02","text":"A memorable experience that we''ll be talking about for years. Professional, fun, and uniquely Portuguese. Don''t hesitate!","source":"getyourguide","verified":true},{"name":"Sven L.","country":"🇨🇭 Switzerland","rating":5,"date":"2025-06-07","text":"The wineries were beautiful and the tastings were generous. Learned so much about Portuguese wine — it''s seriously underrated!","source":"viator","verified":true},{"name":"Katrine H.","country":"🇩🇰 Denmark","rating":5,"date":"2025-05-30","text":"What a wonderful discovery! Portuguese wines are amazing and this tour was the perfect introduction. The port wine at sunset was magical.","source":"viator","verified":true},{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-05-13","text":"Incredible value! Multiple tastings, cheese, gorgeous views, and fascinating stories about Portuguese winemaking tradition.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 16;

-- 17) Experience display_order = 17
UPDATE experiences SET user_reviews = '[{"name":"Lucas F.","country":"🇧🇷 Brazil","rating":5,"date":"2025-12-27","text":"We brought the whole family including our 12-year-old — everyone had a blast. The cataplana was incredible. Best souvenir: the recipes!","source":"getyourguide","verified":true},{"name":"Nadia K.","country":"🇨🇦 Canada","rating":5,"date":"2025-10-24","text":"What a gem! Intimate setting, wonderful chef, and we left with a full belly and a notebook full of recipes. Highly recommended.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-09-28","text":"Hands-on from start to finish. We cooked a full Portuguese meal and ate it together. The recipes work — I''ve already made them at home!","source":"viator","verified":true},{"name":"Ana M.","country":"🇪🇸 Spain","rating":5,"date":"2025-09-25","text":"Great experience! The kitchen was well-equipped and the group was small enough that everyone got hands-on time. Delicious results.","source":"getyourguide","verified":true},{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-09-16","text":"This was my favorite thing we did in Lisbon. The chef made it feel like cooking with a friend, not a class. Absolutely wonderful.","source":"viator","verified":true},{"name":"Olivia C.","country":"🇦🇺 Australia","rating":5,"date":"2025-07-01","text":"Such a fun and delicious experience! We learned to make pastel de nata from scratch. The chef was patient and hilarious. 10/10!","source":"viator","verified":true},{"name":"Sarah M.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-05-30","text":"Loved learning the secrets behind Portuguese cuisine. The dessert was the surprise hit — never would have thought to combine those flavors.","source":"getyourguide","verified":true},{"name":"Mieke D.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-05-22","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":4,"date":"2025-04-02","text":"Good experience overall. A few minor things could be improved but nothing significant. We had a great time. Worth it!","source":"viator","verified":true},{"name":"Nina V.","country":"🇷🇺 Russia","rating":5,"date":"2025-03-19","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 17;

-- 18) Experience display_order = 18
UPDATE experiences SET user_reviews = '[{"name":"Lisa B.","country":"🇩🇪 Germany","rating":5,"date":"2026-01-14","text":"We had an amazing time. The attention to detail was impressive and the staff clearly care about delivering a great experience.","source":"getyourguide","verified":true},{"name":"Pablo V.","country":"🇪🇸 Spain","rating":5,"date":"2025-11-02","text":"Absolutely loved it! As someone who''s normally cautious, the guides made me feel totally safe while still having an amazing adventure.","source":"viator","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":5,"date":"2025-10-14","text":"An unforgettable experience. The crystal-clear water and dramatic coastline made it even more special. Photos came out incredible.","source":"viator","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-07-12","text":"Amazing day out. The instructors were fun and knowledgeable. We saw sea caves, marine life, and had the time of our lives.","source":"getyourguide","verified":true},{"name":"Isabel F.","country":"🇦🇷 Argentina","rating":5,"date":"2025-05-14","text":"A must-do for anyone who loves the outdoors. Professional operation, great equipment, and the natural setting is jaw-dropping.","source":"viator","verified":true},{"name":"Jan V.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-05-13","text":"Thrilling and beautiful at the same time. The instructors were patient and encouraging. We saw the coast from a completely new perspective.","source":"viator","verified":true},{"name":"Rafael O.","country":"🇧🇷 Brazil","rating":5,"date":"2025-04-05","text":"Exceeded our expectations! Everything was professionally run and the experience itself was fantastic. A must-do in Lisbon.","source":"getyourguide","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":5,"date":"2025-03-17","text":"Worth every penny. The combination of sport and stunning scenery was unbeatable. We came back tired but exhilarated.","source":"viator","verified":true},{"name":"James T.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-03-03","text":"My teenage kids said this was the best thing we did in Portugal. That''s the highest compliment! Great guides, great equipment.","source":"viator","verified":true},{"name":"Lucas F.","country":"🇧🇷 Brazil","rating":5,"date":"2025-02-20","text":"Great experience, very well organized. The guide was knowledgeable and friendly. We had an amazing time. Don''t miss this!","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 18;

