UPDATE experiences SET user_reviews = '[{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-12-17","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"getyourguide","verified":true},{"name":"Patrick O.","country":"🇮🇪 Ireland","rating":5,"date":"2025-11-11","text":"The scenery was breathtaking and the activity was so much fun. Perfect mix of adventure and natural beauty. Highly recommend!","source":"viator","verified":true},{"name":"Pablo V.","country":"🇪🇸 Spain","rating":5,"date":"2025-11-02","text":"Absolutely loved it! As someone who''s normally cautious, the guides made me feel totally safe while still having an amazing adventure.","source":"viator","verified":true},{"name":"Carlos G.","country":"🇪🇸 Spain","rating":5,"date":"2025-09-15","text":"An unforgettable experience. The crystal-clear water and dramatic coastline made it even more special. Photos came out incredible.","source":"getyourguide","verified":true},{"name":"Thomas M.","country":"🇩🇪 Germany","rating":5,"date":"2025-07-08","text":"Incredible experience! The water was surprisingly warm and the views of the cliffs from the water were spectacular. Don''t miss this.","source":"viator","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":5,"date":"2025-06-04","text":"A must-do for anyone who loves the outdoors. Professional operation, great equipment, and the natural setting is jaw-dropping.","source":"viator","verified":true},{"name":"Lars E.","country":"🇸🇪 Sweden","rating":5,"date":"2025-05-07","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"getyourguide","verified":true},{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-05-02","text":"Worth every penny. The combination of sport and stunning scenery was unbeatable. We came back tired but exhilarated.","source":"viator","verified":true},{"name":"Antoine D.","country":"🇫🇷 France","rating":4,"date":"2025-04-28","text":"A very enjoyable experience. Good value and well-organized. The guide/instructor was great. Would happily do this again.","source":"viator","verified":true},{"name":"Tom B.","country":"🇦🇺 Australia","rating":4,"date":"2025-04-24","text":"Good experience but bring sunscreen and water! The activity itself was amazing. Instruction was clear and the guides were supportive.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 19;

