UPDATE experiences SET user_reviews = '[{"name":"Yuki T.","country":"🇯🇵 Japan","rating":5,"date":"2025-11-10","text":"A beautiful way to connect with Portuguese culture. The hands-on approach was engaging and the results exceeded our expectations.","source":"getyourguide","verified":true},{"name":"Marco R.","country":"🇮🇹 Italy","rating":5,"date":"2025-09-02","text":"Perfect rainy day activity. We created something beautiful and learned about Portuguese artistic traditions. Very well organized.","source":"viator","verified":true},{"name":"Fatima A.","country":"🇲🇦 Morocco","rating":5,"date":"2025-08-22","text":"Such a unique experience! I''m not artistic at all but the instructor made it accessible and fun. Took home a beautiful souvenir I made myself!","source":"viator","verified":true},{"name":"Hans K.","country":"🇩🇪 Germany","rating":5,"date":"2025-08-20","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"getyourguide","verified":true},{"name":"Ana M.","country":"🇪🇸 Spain","rating":5,"date":"2025-08-02","text":"The instructor''s passion was contagious. We went from complete novices to creating something we''re genuinely proud of. Amazing!","source":"viator","verified":true},{"name":"Lisa B.","country":"🇩🇪 Germany","rating":4,"date":"2025-07-02","text":"Delightful experience! The instructor was a true artist who made the craft feel approachable. We''ll treasure what we made.","source":"viator","verified":true},{"name":"Jennifer K.","country":"🇺🇸 United States","rating":5,"date":"2025-04-29","text":"A memorable experience that we''ll be talking about for years. Professional, fun, and uniquely Portuguese. Don''t hesitate!","source":"getyourguide","verified":true},{"name":"Charlotte D.","country":"🇧🇪 Belgium","rating":5,"date":"2025-02-27","text":"One of the most memorable activities from our trip. The instructor was warm and encouraging. It''s amazing what you can create!","source":"viator","verified":true},{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-02-06","text":"Great experience, very well organized. The guide was knowledgeable and friendly. We had an amazing time. Don''t miss this!","source":"viator","verified":true},{"name":"Ingrid N.","country":"🇸🇪 Sweden","rating":4,"date":"2025-01-31","text":"Good workshop but felt a bit rushed. Would have loved more time to perfect our work. The instructor was great though.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 20;

