top.","source":"viator","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-03-18","text":"Highly recommend! Well-run, engaging, and a lot of fun. One of the best things we did during our stay in Portugal.","source":"viator","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-03-04","text":"Great experience! The kitchen was well-equipped and the group was small enough that everyone got hands-on time. Delicious results.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 21;

