UPDATE experiences SET user_reviews = '[{"name":"Yuki T.","country":"🇯🇵 Japan","rating":5,"date":"2026-01-20","text":"Exceeded our expectations! Everything was professionally run and the experience itself was fantastic. A must-do in Lisbon.","source":"getyourguide","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2026-01-14","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"viator","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-12-25","text":"Absolutely mesmerizing. Even without understanding the words, the emotion in the singer''s voice gave me goosebumps. Unforgettable evening.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-12-06","text":"Deeply moving performance. I didn''t expect to be so affected by music I couldn''t understand. The raw emotion transcended language.","source":"getyourguide","verified":true},{"name":"Fatima A.","country":"🇲🇦 Morocco","rating":4,"date":"2025-11-03","text":"Great show but the venue was quite packed. The music itself was wonderful — the lead singer had an amazing voice.","source":"viator","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":4,"date":"2025-09-01","text":"Nice experience overall. The wine was good and the music was beautiful. Would have liked the show to be a bit longer.","source":"viator","verified":true},{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-05-01","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"getyourguide","verified":true},{"name":"Olivia C.","country":"🇦🇺 Australia","rating":5,"date":"2025-04-14","text":"This is what travel is all about — experiencing something genuinely authentic. The Fado singers poured their souls into every note.","source":"viator","verified":true},{"name":"Nadia K.","country":"🇨🇦 Canada","rating":5,"date":"2025-03-28","text":"If you only do one cultural experience in Lisbon, make it this. The singer was incredible and the atmosphere was pure magic.","source":"viator","verified":true},{"name":"Jennifer K.","country":"🇺🇸 United States","rating":5,"date":"2025-01-30","text":"One of the most powerful live music experiences I''ve ever had. The intimacy of the setting added so much. Left with a full heart.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 22;

-- 23) Experience display_order = 23
UPDATE experiences SET user_reviews = '[{"name":"Robert L.","country":"🇺🇸 United States","rating":4,"date":"2025-10-05","text":"Nice cruise but it was a bit windy and cold. Bring a jacket! The views and wine were great though. Overall a good experience.","source":"getyourguide","verified":true},{"name":"Camila S.","country":"🇧🇷 Brazil","rating":4,"date":"2025-07-15","text":"Good experience overall. Would have loved it to be a bit longer. The wine selection was nice and the crew was very welcoming.","source":"viator","verified":true},{"name":"Andrei C.","country":"🇷🇴 Romania","rating":5,"date":"2025-07-04","text":"The most romantic thing we did in Lisbon. Sailing past the monuments at golden hour with a glass of wine — it doesn''t get better.","source":"viator","verified":true},{"name":"Ana M.","country":"🇪🇸 Spain","rating":5,"date":"2025-07-01","text":"The atmosphere on the boat was fantastic. Good mix of people, great music, and the sunset didn''t disappoint. Will do again!","source":"getyourguide","verified":true},{"name":"Tom B.","country":"🇦🇺 Australia","rating":4,"date":"2025-06-18","text":"A very enjoyable experience. Good value and well-organized. The guide/instructor was great. Would happily do this again.","source":"viator","verified":true},{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-06-15","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"viator","verified":true},{"name":"Ingrid N.","country":"🇸🇪 Sweden","rating":5,"date":"2025-06-14","text":"Relaxing and beautiful. The crew were friendly and professional. Seeing Lisbon from the water gives you a completely different perspective.","source":"getyourguide","verified":true},{"name":"Hans K.","country":"🇩🇪 Germany","rating":5,"date":"2025-04-18","text":"Magical sunset on the Tagus! The light over Lisbon was unreal. The crew was fantastic and the wine kept flowing. Absolutely perfect.","source":"viator","verified":true},{"name":"Giulia P.","country":"🇮🇹 Italy","rating":5,"date":"2025-04-06","text":"One of the highlights of our Lisbon trip. The sunset was absolutely gorgeous and having wine on the water was pure bliss.","source":"viator","verified":true},{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-02-19","text":"Loved it! A unique way to experience Lisbon. The team was professional and the activity was so much fun. Highly recommend.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 23;

