UPDATE experiences SET user_reviews = '[{"name":"Sarah M.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-12-31","text":"Perfect activity for adventure lovers! We had amazing views and great laughs. The guide was professional and friendly.","source":"getyourguide","verified":true},{"name":"Carlos G.","country":"🇪🇸 Spain","rating":5,"date":"2025-12-13","text":"Really well organized tour. The vehicle was fun, the route was scenic, and our guide was both safe and entertaining.","source":"viator","verified":true},{"name":"Lars E.","country":"🇸🇪 Sweden","rating":5,"date":"2025-11-03","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"viator","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-07-31","text":"Unique and memorable experience. We covered a lot of ground and saw some incredible scenery. The guide made it extra special.","source":"getyourguide","verified":true},{"name":"Emma W.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-07-07","text":"Exceeded our expectations! Everything was professionally run and the experience itself was fantastic. A must-do in Lisbon.","source":"viator","verified":true},{"name":"Charlotte D.","country":"🇧🇪 Belgium","rating":4,"date":"2025-06-26","text":"Good tour overall. Would have liked it to be a bit longer. The vehicle was fun and the guide was knowledgeable.","source":"viator","verified":true},{"name":"Giulia P.","country":"🇮🇹 Italy","rating":5,"date":"2025-04-15","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"getyourguide","verified":true},{"name":"Patrick O.","country":"🇮🇪 Ireland","rating":4,"date":"2025-03-30","text":"Fun tour but the vehicle was a bit bumpy on the rough roads. The scenery was gorgeous though and the guide was excellent.","source":"viator","verified":true},{"name":"Pablo V.","country":"🇪🇸 Spain","rating":5,"date":"2025-03-29","text":"An absolute blast! Perfect mix of adventure and sightseeing. The guide was fantastic and knew the best photo spots.","source":"viator","verified":true},{"name":"Sven L.","country":"🇨🇭 Switzerland","rating":5,"date":"2025-03-05","text":"What a unique way to see Lisbon! The ride was so much fun and the views were amazing. Our guide knew all the best spots.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 24;

