UPDATE experiences SET user_reviews = '[{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-12-15","text":"Great experience! The kitchen was well-equipped and the group was small enough that everyone got hands-on time. Delicious results.","source":"getyourguide","verified":true},{"name":"Andrei C.","country":"🇷🇴 Romania","rating":5,"date":"2025-12-08","text":"Fun, informative, and delicious — the perfect combo. We''ve already recreated the bacalhau recipe at home. Our friends were impressed!","source":"viator","verified":true},{"name":"Ana M.","country":"🇪🇸 Spain","rating":5,"date":"2025-11-04","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"viator","verified":true},{"name":"Jan V.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-10-30","text":"Booked this for my mom''s birthday and she was thrilled. Intimate, personal, and delicious. The chef even wrote a recipe card for us.","source":"getyourguide","verified":true},{"name":"Erik J.","country":"🇳🇴 Norway","rating":5,"date":"2025-10-22","text":"Exceeded our expectations! Everything was professionally run and the experience itself was fantastic. A must-do in Lisbon.","source":"viator","verified":true},{"name":"Ingrid N.","country":"🇸🇪 Sweden","rating":5,"date":"2025-08-05","text":"Highly recommend! Well-run, engaging, and a lot of fun. One of the best things we did during our stay in Portugal.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-07-05","text":"What a gem! Intimate setting, wonderful chef, and we left with a full belly and a notebook full of recipes. Highly recommended.","source":"getyourguide","verified":true},{"name":"Giulia P.","country":"🇮🇹 Italy","rating":4,"date":"2025-06-09","text":"A really nice class. Would have liked to cook one more dish, but the quality of what we made was excellent. Chef was very friendly.","source":"viator","verified":true},{"name":"Olivia C.","country":"🇦🇺 Australia","rating":5,"date":"2025-03-15","text":"Great cooking class! The wine pairing with each course was a nice touch. Relaxed atmosphere and everything tasted amazing.","source":"viator","verified":true},{"name":"Miguel A.","country":"🇲🇽 Mexico","rating":5,"date":"2025-01-26","text":"Perfect activity for a rainy day in Lisbon. We laughed, we cooked, we ate way too much. The chef''s stories were the cherry on top.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 26;

