UPDATE experiences SET user_reviews = '[{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-11-13","text":"We did this on our first day and it set the tone for the entire trip. Now we know exactly what to order at restaurants. The wine pairings were perfect.","source":"getyourguide","verified":true},{"name":"Wei L.","country":"🇨🇳 China","rating":5,"date":"2025-10-18","text":"Wonderful tour! Our guide was funny, knowledgeable, and clearly loves what she does. The sardine tasting was surprisingly amazing.","source":"viator","verified":true},{"name":"Sarah M.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-10-11","text":"Wonderful experience! Exactly as described and even better in person. Our guide was outstanding. Highly recommended.","source":"viator","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":4,"date":"2025-10-10","text":"Good food tour but I''ve done better in other cities. The wine and cheese stop was the highlight. Guide was friendly and informative.","source":"getyourguide","verified":true},{"name":"Lucas F.","country":"🇧🇷 Brazil","rating":4,"date":"2025-08-31","text":"A very enjoyable experience. Good value and well-organized. The guide/instructor was great. Would happily do this again.","source":"viator","verified":true},{"name":"Isabel F.","country":"🇦🇷 Argentina","rating":5,"date":"2025-07-03","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"viator","verified":true},{"name":"Giulia P.","country":"🇮🇹 Italy","rating":4,"date":"2025-06-12","text":"A lovely experience overall. Would have liked a bit more variety in the tastings, but the quality was top-notch and the guide was wonderful.","source":"getyourguide","verified":true},{"name":"Nadia K.","country":"🇨🇦 Canada","rating":5,"date":"2025-06-06","text":"Such an authentic experience. Small group, no tourist traps. Our guide took us to a local tasca where we were the only foreigners. Pure gold.","source":"viator","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-04-27","text":"Absolutely fantastic. We discovered flavors we didn''t know existed. The pastéis de bacalhau fresh from the fryer were incredible!","source":"viator","verified":true},{"name":"Yuki T.","country":"🇯🇵 Japan","rating":5,"date":"2025-04-24","text":"Perfect mix of food, culture, and walking through beautiful neighborhoods. Portions were generous — we skipped dinner afterwards!","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 46;

-- 47) Experience display_order = 47
UPDATE experiences SET user_reviews = '[{"name":"Nadia K.","country":"🇨🇦 Canada","rating":5,"date":"2025-10-27","text":"Absolutely mesmerizing. Even without understanding the words, the emotion in the singer''s voice gave me goosebumps. Unforgettable evening.","source":"getyourguide","verified":true},{"name":"Giulia P.","country":"🇮🇹 Italy","rating":5,"date":"2025-10-04","text":"This is what travel is all about — experiencing something genuinely authentic. The Fado singers poured their souls into every note.","source":"viator","verified":true},{"name":"Kim J.","country":"🇰🇷 South Korea","rating":5,"date":"2025-09-30","text":"Exceeded our expectations! Everything was professionally run and the experience itself was fantastic. A must-do in Lisbon.","source":"viator","verified":true},{"name":"Jan V.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-07-16","text":"Emotional, beautiful, and thoroughly Portuguese. The guitarists were masterful. I bought a Fado album on the way out!","source":"getyourguide","verified":true},{"name":"Katrine H.","country":"🇩🇰 Denmark","rating":5,"date":"2025-07-14","text":"A truly special night. Fado is the heartbeat of Lisbon and this experience captures it perfectly. The wine and appetizers were a nice touch.","source":"viator","verified":true},{"name":"Antoine D.","country":"🇫🇷 France","rating":5,"date":"2025-06-08","text":"Brought my partner here for our anniversary trip. We were both spellbound. The emotion in the room was palpable. Book this!","source":"viator","verified":true},{"name":"Carlos G.","country":"🇪🇸 Spain","rating":5,"date":"2025-04-23","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"getyourguide","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-04-16","text":"We had an amazing time. The attention to detail was impressive and the staff clearly care about delivering a great experience.","source":"viator","verified":true},{"name":"Ingrid N.","country":"🇸🇪 Sweden","rating":5,"date":"2025-03-30","text":"Deeply moving performance. I didn''t expect to be so affected by music I couldn''t understand. The raw emotion transcended language.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-02-27","text":"Wonderful evening. The combination of history walk and Fado show was perfect. Guide was knowledgeable and the singers were extraordinary.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 47;

-- 48) Experience display_order = 48
UPDATE experiences SET user_reviews = '[{"name":"Charlotte D.","country":"🇧🇪 Belgium","rating":5,"date":"2026-01-18","text":"So much more than just a tour — it was an adventure! The off-road sections were exciting and the coastal views were incredible.","source":"getyourguide","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-12-22","text":"My husband loved every second of this. Great vehicle, great route, great guide. One of the most fun things we did in Portugal.","source":"viator","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":5,"date":"2025-11-19","text":"A memorable experience that we''ll be talking about for years. Professional, fun, and uniquely Portuguese. Don''t hesitate!","source":"viator","verified":true},{"name":"Olivia C.","country":"🇦🇺 Australia","rating":5,"date":"2025-11-05","text":"Perfect activity for adventure lovers! We had amazing views and great laughs. The guide was professional and friendly.","source":"getyourguide","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-10-04","text":"Really enjoyed this. Good organization, friendly staff, and a memorable experience. Will definitely recommend to friends.","source":"viator","verified":true},{"name":"James T.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-09-26","text":"Wonderful experience! The vehicle was comfortable and well-maintained. Our guide shared fascinating local stories along the way.","source":"viator","verified":true},{"name":"Erik J.","country":"🇳🇴 Norway","rating":5,"date":"2025-09-09","text":"We did this as a birthday treat and it was perfect. Exciting, beautiful, and completely different from anything else in Lisbon.","source":"getyourguide","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-07-23","text":"Great experience, very well organized. The guide was knowledgeable and friendly. We had an amazing time. Don''t miss this!","source":"viat