-- 49) Experience display_order = 49
UPDATE experiences SET user_reviews = '[{"name":"Emma W.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-12-24","text":"We celebrated our anniversary on this cruise. It was intimate, the views were stunning, and the crew made us feel special. Thank you!","source":"getyourguide","verified":true},{"name":"Pablo V.","country":"🇪🇸 Spain","rating":5,"date":"2025-11-14","text":"Really enjoyed this. Good organization, friendly staff, and a memorable experience. Will definitely recommend to friends.","source":"viator","verified":true},{"name":"Jan V.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-11-11","text":"Wonderful experience from start to finish. Small group, great vibes, beautiful sunset. This is what holiday memories are made of.","source":"viator","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-09-18","text":"Perfect activity after a day of walking. Just sit back, relax, and enjoy the views. The Ponte 25 de Abril lit up at night was amazing.","source":"getyourguide","verified":true},{"name":"Kim J.","country":"🇰🇷 South Korea","rating":5,"date":"2025-09-07","text":"Great value for what you get. 2 hours on the water with drinks and snacks. The views of Belém from the river are something special.","source":"viator","verified":true},{"name":"Michael R.","country":"🇺🇸 United States","rating":5,"date":"2025-08-09","text":"Wonderful experience! Exactly as described and even better in person. Our guide was outstanding. Highly recommended.","source":"viator","verified":true},{"name":"Tom B.","country":"🇦🇺 Australia","rating":5,"date":"2025-05-19","text":"The most romantic thing we did in Lisbon. Sailing past the monuments at golden hour with a glass of wine — it doesn''t get better.","source":"getyourguide","verified":true},{"name":"Jennifer K.","country":"🇺🇸 United States","rating":5,"date":"2025-05-07","text":"Book the sunset slot — trust me. The colors over the 25 de Abril bridge were spectacular. Comfortable boat, lovely crew.","source":"viator","verified":true},{"name":"Lars E.","country":"🇸🇪 Sweden","rating":5,"date":"2025-02-21","text":"Incredible experience. The captain shared great stories about Lisbon''s maritime history while we sipped wine. Peaceful and beautiful.","source":"viator","verified":true},{"name":"Mieke D.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-02-16","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 49;

-- 50) Experience display_order = 50
UPDATE experiences SET user_reviews = '[{"name":"Nina V.","country":"🇷🇺 Russia","rating":5,"date":"2025-12-01","text":"Wonderful experience! Exactly as described and even better in person. Our guide was outstanding. Highly recommended.","source":"getyourguide","verified":true},{"name":"Tom B.","country":"🇦🇺 Australia","rating":5,"date":"2025-10-22","text":"Lovely evening with great music and wine. The venue was charming and traditional. Felt like we got to see the real soul of Lisbon.","source":"viator","verified":true},{"name":"Lucas F.","country":"🇧🇷 Brazil","rating":5,"date":"2025-09-11","text":"We were moved to tears. The power of Fado is indescribable until you experience it live. The small venue made it feel so personal.","source":"viator","verified":true},{"name":"Patrick O.","country":"🇮🇪 Ireland","rating":5,"date":"2025-08-25","text":"One of the most powerful live music experiences I''ve ever had. The intimacy of the setting added so much. Left with a full heart.","source":"getyourguide","verified":true},{"name":"Mieke D.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-08-23","text":"This was the most authentic Fado experience in Lisbon. Intimate venue, incredible voices, and the Port wine was excellent. A must!","source":"viator","verified":true},{"name":"Carlos G.","country":"🇪🇸 Spain","rating":5,"date":"2025-08-02","text":"Highly recommend! Well-run, engaging, and a lot of fun. One of the best things we did during our stay in Portugal.","source":"viator","verified":true},{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-07-15","text":"Beautiful performance in an intimate setting. The history of Fado that the guide shared beforehand made us appreciate it even more.","source":"getyourguide","verified":true},{"name":"Hans K.","country":"🇩🇪 Germany","rating":5,"date":"2025-05-01","text":"This is what travel is all about — experiencing something genuinely authentic. The Fado singers poured their souls into every note.","source":"viator","v