UPDATE experiences SET user_reviews = '[{"name":"Antoine D.","country":"🇫🇷 France","rating":5,"date":"2025-10-01","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"getyourguide","verified":true},{"name":"Mieke D.","country":"🇳🇱 Netherlands","rating":5,"date":"2025-09-21","text":"Really enjoyed this. Good organization, friendly staff, and a memorable experience. Will definitely recommend to friends.","source":"viator","verified":true},{"name":"Nina V.","country":"🇷🇺 Russia","rating":5,"date":"2025-09-20","text":"Great value for what you get. 2 hours on the water with drinks and snacks. The views of Belém from the river are something special.","source":"viator","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":5,"date":"2025-09-04","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"getyourguide","verified":true},{"name":"James T.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-08-30","text":"One of the highlights of our Lisbon trip. The sunset was absolutely gorgeous and having wine on the water was pure bliss.","source":"viator","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-07-19","text":"Book the sunset slot — trust me. The colors over the 25 de Abril bridge were spectacular. Comfortable boat, lovely crew.","source":"viator","verified":true},{"name":"Yuki T.","country":"🇯🇵 Japan","rating":5,"date":"2025-05-28","text":"We celebrated our anniversary on this cruise. It was intimate, the views were stunning, and the crew made us feel special. Thank you!","source":"getyourguide","verified":true},{"name":"Carlos G.","country":"🇪🇸 Spain","rating":5,"date":"2025-05-10","text":"Relaxing and beautiful. The crew were friendly and professional. Seeing Lisbon from the water gives you a completely different perspective.","source":"viator","verified":true},{"name":"Lucas F.","country":"🇧🇷 Brazil","rating":5,"date":"2025-03-19","text":"Incredible experience. The captain shared great stories about Lisbon''s maritime history while we sipped wine. Peaceful and beautiful.","source":"viator","verified":true},{"name":"Lars E.","country":"🇸🇪 Sweden","rating":5,"date":"2025-02-21","text":"Wonderful experience from start to finish. Small group, great vibes, beautiful sunset. This is what holiday memories are made of.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 57;

