UPDATE experiences SET user_reviews = '[{"name":"Kim J.","country":"🇰🇷 South Korea","rating":4,"date":"2026-01-20","text":"Good experience overall. A few minor things could be improved but nothing significant. We had a great time. Worth it!","source":"getyourguide","verified":true},{"name":"Fatima A.","country":"🇲🇦 Morocco","rating":5,"date":"2025-12-11","text":"The most luxurious spa experience I''ve ever had. Every detail was perfect — from the robe to the tea afterwards. Heavenly.","source":"viator","verified":true},{"name":"Lisa B.","country":"🇩🇪 Germany","rating":5,"date":"2025-12-04","text":"Highly recommend! The facilities are beautiful, staff is professional, and the treatments are top-notch. A real luxury.","source":"viator","verified":true},{"name":"Charlotte D.","country":"🇧🇪 Belgium","rating":5,"date":"2025-11-18","text":"A bit of heaven in Lisbon. The spa area is gorgeous and the therapists really know what they''re doing. Pure relaxation.","source":"getyourguide","verified":true},{"name":"Yuki T.","country":"🇯🇵 Japan","rating":5,"date":"2025-10-19","text":"A sanctuary of calm in the middle of Lisbon. The staff were attentive without being intrusive. Left floating on air.","source":"viator","verified":true},{"name":"Petra S.","country":"🇩🇪 Germany","rating":5,"date":"2025-07-11","text":"Booked this for my partner''s birthday and it was the perfect gift. Elegant, relaxing, and thoroughly rejuvenating.","source":"viator","verified":true},{"name":"Rafael O.","country":"🇧🇷 Brazil","rating":5,"date":"2025-07-05","text":"Exactly what we needed after days of walking Lisbon''s hills. The massage melted away every bit of tension. Incredible.","source":"getyourguide","verified":true},{"name":"Marco R.","country":"🇮🇹 Italy","rating":5,"date":"2025-03-14","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"viator","verified":true},{"name":"Wei L.","country":"🇨🇳 China","rating":5,"date":"2025-03-04","text":"Wonderful experience! Exactly as described and even better in person. Our guide was outstanding. Highly recommended.","source":"viator","verified":true},{"name":"Robert L.","country":"🇺🇸 United States","rating":5,"date":"2025-02-17","text":"The water circuit was amazing. Pool, sauna, steam room — all immaculate. Added a massage and it was pure heaven.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 58;

