UPDATE experiences SET user_reviews = '[{"name":"Michael R.","country":"🇺🇸 United States","rating":5,"date":"2025-12-05","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"getyourguide","verified":true},{"name":"Patrick O.","country":"🇮🇪 Ireland","rating":5,"date":"2025-11-09","text":"This was my favorite thing we did in Lisbon. The chef made it feel like cooking with a friend, not a class. Absolutely wonderful.","source":"viator","verified":true},{"name":"Camila S.","country":"🇧🇷 Brazil","rating":5,"date":"2025-09-24","text":"Perfect activity for a rainy day in Lisbon. We laughed, we cooked, we ate way too much. The chef''s stories were the cherry on top.","source":"viator","verified":true},{"name":"Nina V.","country":"🇷🇺 Russia","rating":5,"date":"2025-09-16","text":"Wonderful hands-on experience. I appreciated learning about the history behind each dish. The chef''s passion was truly inspiring.","source":"getyourguide","verified":true},{"name":"Thomas M.","country":"🇩🇪 Germany","rating":5,"date":"2025-08-30","text":"Loved learning the secrets behind Portuguese cuisine. The dessert was the surprise hit — never would have thought to combine those flavors.","source":"viator","verified":true},{"name":"Kim J.","country":"🇰🇷 South Korea","rating":5,"date":"2025-08-13","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-07-19","text":"Great experience! The kitchen was well-equipped and the group was small enough that everyone got hands-on time. Delicious results.","source":"getyourguide","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-07-03","text":"Such a fun and delicious experience! We learned to make pastel de nata from scratch. The chef was patient and hilarious. 