UPDATE experiences SET user_reviews = '[{"name":"Marco R.","country":"🇮🇹 Italy","rating":5,"date":"2025-11-21","text":"This was the most authentic Fado experience in Lisbon. Intimate venue, incredible voices, and the Port wine was excellent. A must!","source":"getyourguide","verified":true},{"name":"Ana M.","country":"🇪🇸 Spain","rating":5,"date":"2025-11-09","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"viator","verified":true},{"name":"Fatima A.","country":"🇲🇦 Morocco","rating":4,"date":"2025-11-09","text":"Great show but the venue was quite packed. The music itself was wonderful — the lead singer had an amazing voice.","source":"viator","verified":true},{"name":"Sarah M.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-08-19","text":"Beautiful performance in an intimate setting. The history of Fado that the guide shared beforehand made us appreciate it even more.","source":"getyourguide","verified":true},{"name":"Nadia K.","country":"🇨🇦 Canada","rating":5,"date":"2025-07-18","text":"This is what travel is all about — experiencing something genuinely authentic. The Fado singers poured their souls into every note.","source":"viator","verified":true},{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-06-24","text":"Lovely evening with great music and wine. The venue was charming and traditional. Felt like we got to see the real soul of Lisbon.","source":"viator","verified":true},{"name":"Emma W.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-06-06","text":"Brought my partner here for our anniversary trip. We were both spellbound. The emotion in the room was palpable. Book this!","source":"getyourguide","verified":true},{"name":"Michael R.","country":"🇺🇸 United States","rating":5,"date":"2025-05-29","text":"Emotional, beautiful, and thoroughly Portuguese. The guitarists were masterful. I bought a Fado album on the way out!","source":"viator","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":4,"date":"2025-05-26","text":"Good experience overall. A few minor things could be improved but nothing significant. We had a great time. Worth it!","source":"viator","verified":true},{"name":"Miguel A.","country":"🇲🇽 Mexico","rating":5,"date":"2025-04-03","text":"We had an amazing time. The attention to detail was impressive and the staff clearly care about delivering a great experience.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 64;

