UPDATE experiences SET user_reviews = '[{"name":"Giulia P.","country":"🇮🇹 Italy","rating":5,"date":"2026-01-02","text":"Highly recommend! Well-run, engaging, and a lot of fun. One of the best things we did during our stay in Portugal.","source":"getyourguide","verified":true},{"name":"Marco R.","country":"🇮🇹 Italy","rating":5,"date":"2025-11-24","text":"A lovely way to spend an evening. The boat was comfortable, not too crowded. The Fado music on board was a wonderful surprise.","source":"viator","verified":true},{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-11-20","text":"The most romantic thing we did in Lisbon. Sailing past the monuments at golden hour with a glass of wine — it doesn''t get better.","source":"viator","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":5,"date":"2025-10-24","text":"Magical sunset on the Tagus! The light over Lisbon was unreal. The crew was fantastic and the wine kept flowing. Absolutely perfect.","source":"getyourguide","verified":true},{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-09-11","text":"Really enjoyed this! The captain let us help with the sails which was fun. Great for couples or small groups.","source":"viator","verified":true},{"name":"Jan V.","country":"🇳🇱 Netherlands","rating":4,"date":"2025-08-30","text":"A very enjoyable experience. Good value and well-organized. The guide/instructor was great. Would happily do this again.","source":"viator","verified":true},{"name":"Lars E.","country":"🇸🇪 Sweden","rating":5,"date":"2025-07-23","text":"Incredible experience. The captain shared great stories about Lisbon''s maritime history while we sipped wine. Peaceful and beautiful.","source":"getyourguide","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-03-25","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name