UPDATE experiences SET user_reviews = '[{"name":"Marco R.","country":"🇮🇹 Italy","rating":5,"date":"2025-12-22","text":"Perfect activity for adventure lovers! We had amazing views and great laughs. The guide was professional and friendly.","source":"getyourguide","verified":true},{"name":"Patrick O.","country":"🇮🇪 Ireland","rating":5,"date":"2025-09-03","text":"Great for adrenaline seekers! The terrain was varied and exciting. Safety briefing was thorough and the equipment was top-quality.","source":"viator","verified":true},{"name":"Thomas M.","country":"🇩🇪 Germany","rating":5,"date":"2025-08-15","text":"Such a fantastic experience! We''re so glad we booked this. It was the perfect activity for our trip to Lisbon.","source":"viator","verified":true},{"name":"Priya S.","country":"🇮🇳 India","rating":5,"date":"2025-08-06","text":"So much more than just a tour — it was an adventure! The off-road sections were exciting and the coastal views were incredible.","source":"getyourguide","verified":true},{"name":"Emma W.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-06-02","text":"We did this as a birthday treat and it was perfect. Exciting, beautiful, and completely different from anything else in Lisbon.","source":"viator","verified":true},{"name":"Erik J.","country":"🇳🇴 Norway","rating":5,"date":"2025-05-03","text":"Unique and memorable experience. We covered a lot of ground and saw some incredible scenery. The guide made it extra special.","source":"viator","verified":true},{"name":"Lucas F.","country":"🇧🇷 Brazil","rating":5,"date":"2025-04-18","text":"My husband loved every second of this. Great vehicle, great route, great guide. One of the most fun things we did in Portugal.","source":"getyourguide","verified":true},{"name":"Ingrid N.","country":"🇸🇪 Sweden","rating":4,"date":"2025-03-20","text":"A very enjoyable experience. Good value and well-organized. The guide/instructor was great. Would happily do this again.","source":"viator","verified":true},{"name":"Fatima A.","country":"🇲🇦 Morocco","rating":5,"date":"2025-02-21","text":"Thrilling and scenic! The route took us through beautiful landscapes and the vehicle was an experience in itself. Loved it.","source":"viator","verified":true},{"name":"Hans K.","country":"🇩🇪 Germany","rating":5,"date":"2025-02-11","text":"Great experience, very well organized. The guide was knowledgeable and friendly. We had an amazing time. Don''t miss this!","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 101;

-- 102) Experience display_order = 102
UPDATE experiences SET user_reviews = '[{"name":"Ingrid N.","country":"🇸🇪 Sweden","rating":5,"date":"2026-01-09","text":"Loved it! A unique way to experience Lisbon. The team was professional and the activity was so much fun. Highly recommend.","source":"getyourguide","verified":true},{"name":"Andrei C.","country":"🇷🇴 Romania","rating":4,"date":"2025-11-14","text":"Good experience but bring sunscreen and water! The activity itself was amazing. Instruction was clear and the guides were supportive.","source":"viator","verified":true},{"name":"Fatima A.","country":"🇲🇦 Morocco","rating":5,"date":"2025-09-30","text":"Fun for all fitness levels. Our group had mixed abilities and everyone had a great time. The guides adapted perfectly.","source":"viator","verified":true},{"name":"Sven L.","country":"🇨🇭 Switzerland","rating":5,"date":"2025-08-07","text":"Great adventure activity! Well-organized with all equipment provided. The briefing was thorough and the experience was exhilarating.","source":"getyourguide","verified":true},{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2025-07-21","text":"A memorable experience that we''ll be talking about for years. Professional, fun, and uniquely Portuguese. Don''t hesitate!","source":"viator","verified":true},{"name":"Marie C.","country":"🇫🇷 France","rating":5,"date":"2025-06-16","text":"My teenage kids said this was the best thing we did in Portugal. That''s the highest compliment! Great guides, great equipment.","source":"viator","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-04-09","text":"Amazing day out. The instructors were fun and knowledgeable. We saw sea caves, marine life, and had the time of our lives.","source":"getyourguide","verified":true},{"name":"Ashley P.","country":"🇺🇸 United States","rating":5,"date":"2025-04-07","text":"An unforgettable experience. The crystal-clear water and dramatic coastline made it even more special. Photos came out incredible.","source":"viator","verified":true},{"name":"Nadia K.","country":"🇨🇦 Canada","rating":5,"date":"2025-04-06","text":"Absolutely loved it! As someone who''s normally cautious, the guides made me feel totally safe while still having an amazing adventure.","source":"viator","verified":true},{"name":"Kim J.","country":"🇰🇷 South Korea","rating":5,"date":"2025-04-06","text":"This was definitely worth the price. Great experience, friendly team, and it gave us a new perspective on Lisbon. Loved it.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 102;

-- 103) Experience display_order = 103
UPDATE experiences SET user_reviews = '[{"name":"Yuki T.","country":"🇯🇵 Japan","rating":5,"date":"2025-12-07","text":"Absolutely loved it! As someone who''s normally cautious, the guides made me feel totally safe while still having an amazing adventure.","source":"getyourguide","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-10-09","text":"Fantastic experience from start to finish. Everything was well-coordinated and the team was wonderful. A real highlight.","source":"viator","verified":true},{"name":"Fatima A.","country":"🇲🇦 Morocco","rating":5,"date":"2025-09-29","text":"What an adrenaline rush! The instructor was professional and safety-focused, but we still had an absolute blast. Can''t wait to do it again!","source":"viator","verified":true},{"name":"Lucas F.","country":"🇧🇷 Brazil","rating":5,"date":"2025-07-30","text":"Worth every penny. The combination of sport and stunning scenery was unbeatable. We came back tired but exhilarated.","source":"getyourguide","verified":true},{"name":"Wei L.","country":"🇨🇳 China","rating":5,"date":"2025-07-28","text":"One of the highlights of our Lisbon trip. Well-organized, fun, and great value for money. Would absolutely do it again.","source":"viator","verified":true},{"name":"Sven L.","country":"🇨🇭 Switzerland","rating":5,"date":"2025-06-02","text":"A must-do for anyone who loves the outdoors. Professional operation, great equipment, and the natural setting is jaw-dropping.","source":"viator","verified":true},{"name":"Pablo V.","country":"🇪🇸 Spain","rating":5,"date":"2025-05-22","text":"Great experience, very well organized. The guide was knowledgeable and friendly. We had an amazing time. Don''t miss this!","source":"getyourguide","verified":true},{"name":"Miguel A.","country":"🇲🇽 Mexico","rating":4,"date":"2025-04-25","text":"Good experience but bring sunscreen and water! The activity itself was amazing. Instruction was clear and the guides were supportive.","source":"viator","verified":true},{"name":"Ana M.","country":"🇪🇸 Spain","rating":5,"date":"2025-04-14","text":"Amazing day out. The instructors were fun and knowledgeable. We saw sea caves, marine life, and had the time of our lives.","source":"viator","verified":true},{"name":"Sarah M.","country":"🇬🇧 United Kingdom","rating":5,"date":"2025-03-30","text":"Great adventure activity! Well-organized with all equipment provided. The briefing was thorough and the experience was exhilarating.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 103;

