UPDATE experiences SET user_reviews = '[{"name":"Sophie L.","country":"🇫🇷 France","rating":5,"date":"2026-01-11","text":"A memorable experience that we''ll be talking about for years. Professional, fun, and uniquely Portuguese. Don''t hesitate!","source":"getyourguide","verified":true},{"name":"Helena R.","country":"🇵🇱 Poland","rating":5,"date":"2025-12-29","text":"An unforgettable experience. The aerial perspective of the coastline and the city was something I''ll remember forever. Worth every cent.","source":"viator","verified":true},{"name":"David H.","country":"🇺🇸 United States","rating":5,"date":"2025-11-16","text":"Professional operation with top safety standards. Once airborne, the scenery was absolutely magnificent. Don''t hesitate — book it!","source":"viator","verified":true},{"name":"Nina V.","country":"🇷🇺 Russia","rating":5,"date":"2025-10-27","text":"Wanted to do this for years and it lived up to every expectation. The crew was amazing and the experience was flawless.","source":"getyourguide","verified":true},{"name":"Martin P.","country":"🇨🇿 Czech Republic","rating":5,"date":"2025-10-06","text":"We had an amazing time. The attention to detail was impressive and the staff clearly care about delivering a great experience.","source":"viator","verified":true},{"name":"Lucas F.","country":"🇧🇷 Brazil","rating":5,"date":"2025-08-07","text":"Loved it! A unique way to experience Lisbon. The team was professional and the activity was so much fun. Highly recommend.","source":"viator","verified":true},{"name":"Michael R.","country":"🇺🇸 United States","rating":5,"date":"2025-07-28","text":"I gifted this to my partner and we both screamed with joy! Safe, thrilling, and beautiful. Best gift I''ve ever given.","source":"getyourguide","verified":true},{"name":"Miguel A.","country":"🇲🇽 Mexico","rating":5,"date":"2025-07-23","text":"Best money we spent on our trip. The experience was smooth, safe, and the views were absolutely jaw-dropping. Magical.","source":"viator","verified":true},{"name":"Pablo V.","country":"🇪🇸 Spain","rating":5,"date":"2025-07-06","text":"Surreal experience. The takeoff was exhilarating and the panoramic views were beyond anything I''d imagined. Just WOW.","source":"viator","verified":true},{"name":"Kim J.","country":"🇰🇷 South Korea","rating":5,"date":"2025-06-21","text":"Absolutely spectacular! The conditions were perfect and the views stretched forever. The pilot/instructor was fantastic.","source":"getyourguide","verified":true}]'::jsonb WHERE display_order = 104;

